"use client";

import { useState } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { X, ArrowUpRight } from "lucide-react";
import { Button } from "@/components/ui/button";

interface AuthModalProps {
    isOpen: boolean;
    onClose: () => void;
}

export function AuthModal({ isOpen, onClose }: AuthModalProps) {
    const [activeTab, setActiveTab] = useState<"login" | "signup">("login");

    return (
        <AnimatePresence>
            {isOpen && (
                <>
                    {/* Backdrop Overlay & Modal Container */}
                    <motion.div
                        className="fixed inset-0 bg-black/40 backdrop-blur-md z-[50] flex items-center justify-center p-4 sm:p-10 pt-[80px]"
                        initial={{ opacity: 0 }}
                        animate={{ opacity: 1 }}
                        exit={{ opacity: 0 }}
                        onClick={onClose}
                    >
                        <motion.div
                            onClick={(e) => e.stopPropagation()}
                            className="bg-white rounded-[1.25rem] w-full max-w-[520px] overflow-hidden shadow-2xl relative flex flex-col cursor-auto"
                            initial={{ scale: 0.95, opacity: 0, y: 10 }}
                            animate={{ scale: 1, opacity: 1, y: 0 }}
                            exit={{ scale: 0.95, opacity: 0, y: 10 }}
                            transition={{ type: "spring", duration: 0.5, bounce: 0.3 }}
                        >
                            {/* Top Tabs */}
                            <div className="flex w-full relative z-0">
                                <button
                                    onClick={() => setActiveTab("login")}
                                    className={`flex-1 py-[16px] text-center text-[25px] transition-colors relative font-[700] ${activeTab === "login"
                                        ? "text-[#DE0A26] border-b-[3px] border-[#DE0A26]"
                                        : "text-[#8C959F] border-b-[3px] border-[#1e2329]"
                                        }`}
                                >
                                    Login
                                </button>
                                {/* Vertical Divider */}
                                <div className="absolute left-1/2 top-0 bottom-0 w-[1px] bg-gray-200" />
                                <button
                                    onClick={() => setActiveTab("signup")}
                                    className={`flex-1 py-[16px] text-center text-[25px] transition-colors relative font-[700] ${activeTab === "signup"
                                        ? "text-[#DE0A26] border-b-[3px] border-[#DE0A26]"
                                        : "text-[#8C959F] border-b-[3px] border-[#1e2329]"
                                        }`}
                                >
                                    Signup
                                </button>
                            </div>

                            {/* Internal Content Container */}
                            <div className="px-6 pt-6 pb-6 w-full flex flex-col items-center">
                                {/* Header section */}
                                <div className="text-center w-full mb-5">
                                    <h2 className="text-[17px] font-[500] text-[#57606a] tracking-tight flex items-center justify-center gap-1.5">
                                        Welcome to <span className="font-[800] text-[#1e2329] text-[25px]">My Travel Deal!</span>
                                    </h2>
                                    <p className="text-[15px] sm:text-[20px] font-[600] text-[#8C959F] mt-1 tracking-tight">
                                        Please {activeTab === "login" ? "Login" : "Signup"} Using Your Email/Mobile To Continue
                                    </p>
                                </div>

                                {/* Pink Background Card */}
                                <div className="bg-rose-50/30 rounded-[1.25rem] w-full p-6 sm:px-8 pb-7 border border-rose-100/50">
                                    <div className="flex flex-col gap-6 w-full">
                                        {/* Input Field: Email/Mobile */}
                                        <div className="flex flex-col">
                                            <label
                                                htmlFor="identifier"
                                                className="text-[20px] font-[700] text-[#1e2329] mb-1"
                                            >
                                                Email Id / Mobile Number
                                            </label>
                                            <input
                                                type="text"
                                                id="identifier"
                                                className="w-full border-0 border-b border-[#d1d5db] bg-transparent py-1.5 px-0 text-[14px] font-[600] text-[#1e2329] focus:border-[#DE0A26] focus:outline-none focus:ring-0"
                                            />
                                        </div>

                                        {/* Input Field: Password */}
                                        <div className="flex flex-col relative">
                                            <label
                                                htmlFor="password"
                                                className="text-[20px] font-[700] text-[#1e2329] mb-1"
                                            >
                                                Password
                                            </label>
                                            <input
                                                type="password"
                                                id="password"
                                                className="w-full border-0 border-b border-[#d1d5db] bg-transparent py-1.5 px-0 text-[14px] font-[600] text-[#1e2329] focus:border-[#DE0A26] focus:outline-none focus:ring-0"
                                            />
                                        </div>

                                        {/* Forgot Password Link */}
                                        <div className="flex justify-end mt-[-8px]">
                                            {activeTab === "login" ? (
                                                <button type="button" className="text-[#DE0A26] text-[20px] font-[600] hover:underline cursor-pointer">
                                                    Forgot Password
                                                </button>
                                            ) : (
                                                <div className="h-[15px]"></div>
                                            )}
                                        </div>
                                    </div>

                                    {/* Primary Action Button */}
                                    <div className="mt-8 flex justify-center w-full">
                                        <Button
                                            className="w-full sm:w-[90%] md:w-[85%] rounded-[100px] bg-[#DE0A26] hover:bg-[#c60823] text-white h-[50px] text-[22px] font-[700] tracking-wide shadow-none transition-transform hover:scale-105 active:scale-95 flex items-center justify-center gap-2"
                                        >
                                            {activeTab === "login" ? "Login" : "Signup"}
                                            <ArrowUpRight className="w-[18px] h-[18px] stroke-[2.5px]" />
                                        </Button>
                                    </div>
                                </div>
                            </div>
                        </motion.div>
                    </motion.div>
                </>
            )}
        </AnimatePresence>
    );
}

"use client";

import { PlaneTakeoff, PlaneLanding, Clock } from "lucide-react";

export type Flight = {
    id: string;
    airline: string;
    origin: string;
    destination: string;
    departureTime: string;
    arrivalTime: string;
    duration: string;
    price: number;
    stops: number;
};

export function FlightResults({ flights, isLoading }: { flights: Flight[], isLoading: boolean }) {
    if (isLoading) {
        return (
            <div className="w-full flex justify-center py-12">
                <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary"></div>
            </div>
        );
    }

    if (flights.length === 0) {
        return (
            <div className="w-full text-center py-12 bg-white rounded-xl shadow-sm border border-slate-100">
                <h3 className="text-xl font-bold text-slate-700">No flights found</h3>
                <p className="text-slate-500 mt-2">Try adjusting your search criteria</p>
            </div>
        );
    }

    return (
        <div className="w-full space-y-4 max-w-4xl mx-auto mt-8">
            <h3 className="text-xl font-bold text-slate-900 mb-6">Available Flights</h3>

            {flights.map((flight) => (
                <div key={flight.id} className="bg-white rounded-xl shadow-sm border border-slate-100 p-6 flex flex-col md:flex-row items-center justify-between gap-6 hover:shadow-md transition-shadow">

                    <div className="flex items-center gap-4 w-full md:w-auto">
                        <div className="w-12 h-12 bg-primary/10 rounded-full flex items-center justify-center text-primary font-bold text-xl">
                            {flight.airline.charAt(0)}
                        </div>
                        <div>
                            <p className="font-bold text-slate-900">{flight.airline}</p>
                            <p className="text-sm text-slate-500">{flight.id}</p>
                        </div>
                    </div>

                    <div className="flex items-center gap-8 w-full md:w-auto flex-1 justify-center">
                        <div className="text-center">
                            <p className="font-bold text-xl text-slate-900">{flight.departureTime}</p>
                            <p className="text-sm text-slate-500">{flight.origin}</p>
                        </div>

                        <div className="flex flex-col items-center flex-1 max-w-[200px]">
                            <p className="text-xs text-slate-500 mb-1 flex items-center gap-1">
                                <Clock className="w-3 h-3" /> {flight.duration}
                            </p>
                            <div className="w-full relative flex items-center justify-center">
                                <div className="absolute w-full h-[2px] bg-slate-200"></div>
                                <PlaneTakeoff className="w-4 h-4 text-primary relative z-10 bg-white px-0.5" />
                            </div>
                            <p className="text-xs font-semibold text-primary mt-1">
                                {flight.stops === 0 ? "Non-stop" : `${flight.stops} Stop`}
                            </p>
                        </div>

                        <div className="text-center">
                            <p className="font-bold text-xl text-slate-900">{flight.arrivalTime}</p>
                            <p className="text-sm text-slate-500">{flight.destination}</p>
                        </div>
                    </div>

                    <div className="flex flex-col md:items-end w-full md:w-auto gap-2 border-t md:border-t-0 pt-4 md:pt-0 border-slate-100">
                        <p className="text-2xl font-extrabold text-slate-900">
                            ₹{flight.price.toLocaleString('en-IN')}
                        </p>
                        <button className="bg-primary text-white font-bold py-2 px-6 rounded-lg hover:bg-primary/90 transition-colors w-full md:w-auto">
                            Book Now
                        </button>
                    </div>

                </div>
            ))}
        </div>
    );
}

"use client";

import * as React from "react";
import { format } from "date-fns";
import { PlaneTakeoff, ArrowRightLeft, ArrowUpRight, ChevronDown } from "lucide-react";

import { cn } from "@/lib/utils";
import { Button } from "@/components/ui/button";
import { Calendar } from "@/components/ui/calendar";
import {
    Popover,
    PopoverContent,
    PopoverTrigger,
} from "@/components/ui/popover";

interface FlightSearchProps {
    onSearch?: (searchData: { origin: string; destination: string; nonStop: boolean }) => void;
}

export function FlightSearch({ onSearch }: FlightSearchProps) {
    const [date, setDate] = React.useState<Date>();
    const [returnDate, setReturnDate] = React.useState<Date>();
    const [tripType, setTripType] = React.useState<"one-way" | "round-trip" | "multi-city">("one-way");

    const [origin, setOrigin] = React.useState("New Delhi");
    const [destination, setDestination] = React.useState("Mumbai");
    const [nonStop, setNonStop] = React.useState(false);

    const handleSearch = () => {
        if (onSearch) {
            onSearch({ origin, destination, nonStop });
        }
    };

    return (
        <div className="h-[340px] w-full max-w-[1500px] xl:max-w-full mx-auto bg-white rounded-[1.5rem] flex flex-col pt-4 relative z-10 font-sans shadow-xl">
            {/* Top Navigation Row */}
            <div className="flex items-center justify-between border-b border-slate-100 bg-white rounded-t-[1.5rem]">
                <div className="flex px-10 pt-0 pb-4 bg-white relative border-b-4 border-[#E11D48] text-[#E11D48]">
                    <div className="flex items-center gap-2 font-bold text-[22px]">
                        <PlaneTakeoff className="w-8 h-8" strokeWidth={2.5} />
                        <span className="tracking-tight">Flights</span>
                    </div>
                </div>
                <div className="flex items-center text-[19px] font-semibold pr-4">
                    <div className="flex items-center gap-1.5 px-6 py-4 cursor-pointer text-slate-400 hover:text-slate-600 transition-colors">
                        <span>Last Searches</span>
                        <ChevronDown className="w-5 h-5" />
                    </div>
                    <div className="px-6 py-4 border-l border-slate-200 cursor-pointer text-slate-400 hover:text-slate-600 transition-colors">
                        Reset Search
                    </div>
                </div>
            </div>

            <div className="px-10 py-8 flex flex-col gap-6">
                {/* Trip Type Selector */}
                <div className="flex items-center space-x-6">
                    {(["one-way", "round-trip", "multi-city"] as const).map((type) => (
                        <label key={type} className="flex items-center space-x-2 cursor-pointer group">
                            <div className={cn(
                                "w-[20px] h-[20px] rounded-full border-2 flex items-center justify-center transition-colors shadow-sm",
                                tripType === type ? "border-[#E11D48]" : "border-slate-300 group-hover:border-slate-400"
                            )}>
                                {tripType === type && <div className="w-3 h-3 rounded-full bg-[#E11D48]" />}
                            </div>
                            <span className={cn(
                                "text-[18px] transition-colors leading-none pt-0.5",
                                tripType === type ? "text-slate-800 font-bold" : "text-slate-400 font-semibold group-hover:text-slate-600"
                            )}>
                                {type === 'one-way' ? 'One Way' : type === 'round-trip' ? 'Round Trip' : 'Multi City'}
                            </span>
                        </label>
                    ))}
                </div>

                {/* Search Fields Form */}
                <div className="flex flex-col lg:flex-row items-start justify-between w-full mt-2 lg:gap-2 xl:gap-6 relative">

                    {/* 1. Departure From */}
                    <div className="flex flex-col flex-1 min-w-[210px] group relative h-[100px]">
                        <label className="text-[18px] font-bold text-slate-400 mb-2 block">Departure From</label>
                        <input
                            type="text"
                            className="bg-transparent border-none font-bold text-slate-900 tracking-tighter text-[30px] p-0 placeholder:text-slate-300 leading-none h-[34px] w-full"
                            value={origin}
                            onChange={(e) => setOrigin(e.target.value)}
                        />
                        <p className="text-[15px] text-slate-500 mt-2 truncate font-medium">DEL, Indira Gandhi Int...</p>
                        <div className="absolute bottom-[-10px] left-0 w-full h-[1.5px] bg-slate-200 group-hover:bg-slate-300 transition-colors" />
                    </div>

                    {/* Swap Button */}
                    <div className="hidden lg:flex absolute left-[min(20%,_300px)] xl:left-[20%] top-[35%] -translate-x-1/2 -translate-y-1/2 z-10 w-8 h-8 rounded-full border border-[#E11D48] bg-white text-[#E11D48] cursor-pointer hover:bg-red-50 transition-colors items-center justify-center pt-[1px]">
                        <ArrowRightLeft className="w-4 h-4 text-[#E11D48]" strokeWidth={2.5} />
                    </div>

                    {/* 2. Going To */}
                    <div className="flex flex-col flex-1 min-w-[210px] group relative h-[100px] lg:pl-6 xl:pl-4">
                        <label className="text-[18px] font-bold text-slate-400 mb-2 block">Going To</label>
                        <input
                            type="text"
                            className="bg-transparent border-none outline-none font-bold text-slate-900 tracking-tighter text-[30px] p-0 placeholder:text-slate-300 leading-none h-[34px] w-full"
                            value={destination}
                            onChange={(e) => setDestination(e.target.value)}
                        />
                        <p className="text-[15px] text-slate-500 mt-2 truncate font-medium">BOM, Chhatrapati Shi...</p>
                        <div className="absolute bottom-[-10px] left-0 w-full h-[1.5px] bg-slate-200 group-hover:bg-slate-300 transition-colors lg:ml-6 xl:ml-4 lg:w-[calc(100%-24px)] xl:w-[calc(100%-16px)]" />
                    </div>

                    <Popover>
                        <PopoverTrigger asChild>
                            <div className="flex flex-col w-[170px] xl:w-[190px] group cursor-pointer relative h-[100px]">
                                <label className="text-[18px] font-bold text-slate-400 mb-2 flex items-center gap-1 cursor-pointer">
                                    Departure Date
                                    <ChevronDown className="w-4 h-4" strokeWidth={3} />
                                </label>
                                <div className="font-bold text-slate-900 tracking-tighter text-[30px] leading-none h-[34px] flex items-center">
                                    {date ? format(date, "dd MMM' yy") : <span>24 Sep' 25</span>}
                                </div>
                                <p className="text-[15px] text-slate-500 mt-2 font-medium">{date ? format(date, "EEEE") : "Wednesday"}</p>
                                <div className="absolute bottom-[-10px] left-0 w-full h-[1.5px] bg-slate-200 group-hover:bg-slate-300 transition-colors" />
                            </div>
                        </PopoverTrigger>
                        <PopoverContent className="w-auto p-0" align="start">
                            <Calendar mode="single" selected={date} onSelect={setDate} initialFocus />
                        </PopoverContent>
                    </Popover>

                    {/* 4. Return Date */}
                    <Popover>
                        <PopoverTrigger asChild>
                            <div className={cn(
                                "flex flex-col w-[170px] xl:w-[190px] group cursor-pointer relative h-[100px]",
                                tripType === 'one-way' ? "cursor-default" : ""
                            )}>
                                <label className="text-[18px] font-bold text-slate-400 mb-2 block cursor-pointer">Return Date</label>
                                <div className="h-[52px] flex items-start pt-[2px]">
                                    {returnDate && tripType !== 'one-way' ? (
                                        <div className="font-black text-slate-900 tracking-tighter text-[30px] leading-none">
                                            {format(returnDate, "dd MMM' yy")}
                                            <p className="text-[15px] text-slate-500 mt-2 font-medium tracking-normal">{format(returnDate, "EEEE")}</p>
                                        </div>
                                    ) : (
                                        <span className="text-[#3b82f6] text-[17px] font-semibold leading-[1.3] tracking-tight">
                                            Book Round Trip<br />To Save Extra
                                        </span>
                                    )}
                                </div>
                                <div className="absolute bottom-[-10px] left-0 w-full h-[1.5px] bg-slate-200 group-hover:bg-slate-300 transition-colors" />
                            </div>
                        </PopoverTrigger>
                        <PopoverContent className="w-auto p-0" align="start">
                            <Calendar mode="single" selected={returnDate} onSelect={setReturnDate} initialFocus />
                        </PopoverContent>
                    </Popover>

                    <div className="flex flex-col w-[170px] xl:w-[190px] group cursor-pointer relative h-[100px]">
                        <label className="text-[18px] font-bold text-slate-400 mb-2 flex items-center gap-1">
                            Travellers & Class
                            <ChevronDown className="w-4 h-4" strokeWidth={3} />
                        </label>
                        <div className="font-bold text-slate-900 tracking-tighter text-[30px] leading-none h-[34px] flex items-center">
                            1 Traveller
                        </div>
                        <p className="text-[15px] text-slate-500 mt-2 font-medium">Economy</p>
                        <div className="absolute bottom-[-10px] left-0 w-full h-[1.5px] bg-slate-200 group-hover:bg-slate-300 transition-colors" />
                    </div>

                    {/* 6. Search Button */}
                    <div className="flex items-center justify-end h-[88px] pb-2 pl-5">
                        <Button
                            onClick={handleSearch}
                            className="bg-[#E11D48] hover:bg-[#BE123C] text-white rounded-full px-10 py-7 h-[60px] text-[20px] font-bold transition-transform hover:scale-105 active:scale-95 shadow-md flex items-center gap-1.5"
                        >
                            Search
                            <ArrowUpRight className="w-6 h-6" strokeWidth={2.5} />
                        </Button>
                    </div>
                </div>

                {/* Checkbox for Non-Stop */}
                <div className="flex items-center space-x-2.5 mt-2">
                    <button
                        id="nonStop"
                        onClick={() => setNonStop(!nonStop)}
                        className={cn(
                            "w-[18px] h-[18px] rounded-[4px] border flex items-center justify-center transition-colors shadow-sm",
                            nonStop ? "bg-[#E11D48] border-[#E11D48] text-white" : "border-slate-300 bg-white"
                        )}
                    >
                        {nonStop && <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}><path strokeLinecap="round" strokeLinejoin="round" d="M5 13l4 4L19 7" /></svg>}
                    </button>
                    <label htmlFor="nonStop" className="text-[15px] font-bold text-slate-400 cursor-pointer pt-[2px]" onClick={() => setNonStop(!nonStop)}>
                        Non- Stops Flights
                    </label>
                </div>
            </div>
        </div>
    );
}
